<?php
 namespace WPAICG\AutoGPT\Cron\EventProcessor\Trigger\Modules; if (!defined('ABSPATH')) { exit; } function apply_include_exclude_keywords_logic(array $items, string $include_keywords_str, string $exclude_keywords_str): array { if (empty($include_keywords_str) && empty($exclude_keywords_str)) { return $items; } $include_keywords = !empty($include_keywords_str) ? array_map('trim', explode(',', strtolower($include_keywords_str))) : []; $exclude_keywords = !empty($exclude_keywords_str) ? array_map('trim', explode(',', strtolower($exclude_keywords_str))) : []; return array_filter($items, function ($item) use ($include_keywords, $exclude_keywords) { if (!isset($item['title'])) { return false; } $title_lower = strtolower($item['title']); if (!empty($exclude_keywords)) { foreach ($exclude_keywords as $keyword) { if ($keyword !== '' && str_contains($title_lower, $keyword)) { return false; } } } if (!empty($include_keywords)) { foreach ($include_keywords as $keyword) { if ($keyword !== '' && str_contains($title_lower, $keyword)) { return true; } } return false; } return true; }); } 